description:
Files: runtime/src/heap.rs, src/runtime.rs

Replace gc() and gc_mid_flight() dispatch with minor/major selection:

fn should_run_major(&self) -> bool {
  self.minor_gc_count >= 10
  || (self.old_top as usize - self.old_start as usize) > (self.old_end as usize - self.old_start as usize) * 7 / 10
}

gc_mid_flight (called from run_quantum):
  if should_run_major() { gc_major(roots, mailbox) }
  else { gc_minor(roots, mailbox) }

park_time_gc (called from run_quantum at parked_cont wakeup):
  let root_bits = parked_cont as usize as u64;
  let mut roots = [FzValue(root_bits)];
  let mut empty_mailbox = VecDeque::new();  // mailbox empty at park time
  if should_run_major() { gc_major(&mut roots, &mut empty_mailbox) }
  else { gc_minor(&mut roots, &mut empty_mailbox) }
  process.parked_cont = roots[0].unbox_ptr() as *mut u8;

Tests: after 10 minor GCs, next call to gc_mid_flight triggers major. When old block is 71% full, should_run_major() returns true. Below thresholds, gc_minor() is called.
